284	export type SelectionSetRule = {
285	  field: 'category' | 'level' | 'typeName';
286	  operator: 'equals' | 'contains';
287	  value: string;
288	  /**
289	   * FED-02: which models the rule resolves against. `'host'` (default) only
290	   * matches host elements; `'all_links'` walks every `link_model` element and
291	   * matches inside source models too; `{ specificLinkId }` restricts to one
292	   * link. Linked element AABBs are transformed by the link's positionMm +
293	   * rotationDeg before clash-checking.
294	   */
295	  linkScope?: 'host' | 'all_links' | { specificLinkId: string };
296	};
