298	/**
299	 * FED-03: structured monitor-source pointer used by Copy/Monitor.
300	 *
301	 * `linkId` (when set) names a `link_model` element in the host whose source
302	 * model contains the monitored element; intra-host monitors omit it.
303	 * `elementId` is the **source-side** id (not the `<linkId>::<sourceElemId>`
304	 * prefixed form). `sourceRevisionAtCopy` is the source model's revision
305	 * counter at the moment of the copy; the BumpMonitoredRevisions command
306	 * compares it against the latest revision and flags drift.
307	 *
308	 * `drifted` and `driftedFields` are computed by BumpMonitoredRevisions; they
309	 * persist on the host element so the constraint evaluator can emit a
310	 * `monitored_source_drift` advisory without needing live source access.
311	 */
312	export type MonitorSource = {
313	  linkId?: string | null;
314	  elementId: string;
315	  sourceRevisionAtCopy: number;
316	  drifted?: boolean;
317	  driftedFields?: string[];
318	};
