1379	      longitudeDeg: number;
1380	      dateIso: string;
1381	      timeOfDay: { hours: number; minutes: number };
1382	      animationRange?: { startIso: string; endIso: string; intervalMinutes: number } | null;
1383	      daylightSavingStrategy: 'auto' | 'on' | 'off';
1384	    };
1385	
1386	export type Violation = {
1387	  ruleId: string;
1388	
1389	  severity: 'info' | 'warning' | 'error';
1390	
1391	  message: string;
1392	
1393	  elementIds?: string[];
1394	
