1405	
1406	  revision: number;
1407	
1408	  elements: Record<string, unknown>;
1409	
1410	  violations: Violation[];
1411	
1412	  /**
1413	   * FED-01 polish: per-source-uuid current revision for every `link_model`
1414	   * row, used by the UI to render drift badges on pinned links. Omitted when
1415	   * the host has no links.
1416	   */
1417	  linkSourceRevisions?: Record<string, number>;
1418	};
