1434	  type: string;
1435	};
1436	
1437	/**
1438	 * SKB-02 — auto-extract walls + floor + roof-stub from a `mass` element.
1439	 * The engine emits one wall per footprint segment, one floor matching
1440	 * the footprint at level base, and one flat roof at level base + heightMm,
1441	 * promotes phase to `'skeleton'` on emitted elements, and deletes the mass.
